delete from FileTasks where operation_id=?1;
delete from PackageTasks where operation_id=?1;
delete from Operations where operation_id=?1;

delete from PackagesToPaths where PackagesToPaths.build_id in (
    select Builds.build_id from Builds
        left outer join Operations on
            Operations.build_id == Builds.build_id
    where Operations.build_id is null
);

